import{c as e}from"./app.39e71802.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const p={},a=e('<p>\u77E5\u6211\u8005\u8C13\u6211\u5FC3\u5FE7\uFF0C\u4E0D\u77E5\u6211\u8005\u8C13\u6211\u4F55\u6C42</p><h2 id="\u5F15\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5F15\u8A00" aria-hidden="true">#</a> \u5F15\u8A00</h2><p>\u5F53\u4ECA\uFF0CVue.js\u3001React\u7B49\u4F18\u79C0\u5F00\u6E90\u6846\u67B6\u5728Web\u524D\u7AEF\u9886\u57DF\u5DF2\u7ECF\u7EA2\u4E86\u534A\u8FB9\u5929\uFF0C\u719F\u7EC3\u638C\u63E1\u4E00\u95E8\u6846\u67B6\u5DF2\u7136\u6210\u4E3A\u4E86\u6BCF\u4E00\u540DWeb\u524D\u7AEF\u9886\u57DF\u4ECE\u4E1A\u8005\u5FC5\u5907\u7684\u6280\u672F\u7D20\u517B\u3002\u800C\u5728\u5B66\u4E60\u6846\u67B6\u7684\u8FC7\u7A0B\u4E4B\u4E2D\uFF0C\u4F60\u6709\u6CA1\u6709\u60F3\u8FC7\u8FD9\u4E2A\u6846\u67B6\u662F\u5982\u4F55\u8BBE\u8BA1\u7684\uFF1F\u5B83\u4E3A\u4EC0\u4E48\u8981\u8FD9\u4E48\u8BBE\u8BA1\uFF1F\u6DF1\u601D\u8D77\u6765\uFF0C\u8981\u60F3\u8BBE\u8BA1\u4E00\u4E2A\u4F18\u79C0\u7684\u6846\u67B6\u8981\u6BD4\u60F3\u8C61\u4E2D\u7684\u590D\u6742\u8BB8\u591A\uFF0C\u5E76\u4E0D\u662F\u8BF4\u628A\u76F8\u5173\u7684\u529F\u80FD\u5168\u90E8\u5F00\u53D1\u5B8C\u6210\u5C31\u5927\u529F\u544A\u6210\u4E86\uFF0C\u201C\u80FD\u7528\u201D\u53EA\u662F\u6700\u57FA\u672C\u7684\u8981\u6C42\uFF0C\u201C\u597D\u7528\u201D\u624D\u5177\u5907\u6838\u5FC3\u7ADE\u4E89\u529B\uFF01\u672C\u6587\u4E3B\u8981\u4EE5Vue.js\u4E3A\u4F8B\uFF0C\u56F4\u7ED5\u8BBE\u8BA1\u4E00\u4E2A\u4F18\u79C0\u7684\u6846\u67B6\u8C08\u4E00\u8C08\u8981\u8003\u8651\u5230\u7684\u65B9\u65B9\u9762\u9762\u3002</p><h2 id="\u63D0\u5347\u7528\u6237\u7684\u5F00\u53D1\u4F53\u9A8C" tabindex="-1"><a class="header-anchor" href="#\u63D0\u5347\u7528\u6237\u7684\u5F00\u53D1\u4F53\u9A8C" aria-hidden="true">#</a> \u63D0\u5347\u7528\u6237\u7684\u5F00\u53D1\u4F53\u9A8C</h2><p>\u662F\u5426\u62E5\u6709\u826F\u597D\u7684\u5F00\u53D1\u4F53\u9A8C\u662F\u8861\u91CF\u4E00\u4E2A\u6846\u67B6\u662F\u5426\u8DB3\u591F\u4F18\u79C0\u7684\u91CD\u8981\u6307\u6807\u4E4B\u4E00\uFF0C\u662F\u4E00\u4E2A\u6846\u67B6\u80FD\u5426\u8FC5\u901F\u63A8\u5E7F\u3001\u666E\u53CA\u7684\u57FA\u77F3\u3002\u5C31\u5982\u6211\u4EEC\u65E5\u5E38\u751F\u6D3B\u4E2D\uFF0C\u90A3\u4E9B\u771F\u6B63\u597D\u7528\u7684\u73A9\u610F\u5411\u6765\u4E0D\u7F3A\u62E5\u8DB8\uFF08dun\uFF09\u8005\uFF0C\u800C\u53E6\u4E00\u4E9B\u53CD\u4EBA\u7C7B\u7684\u8BBE\u8BA1\u5F80\u5F80\u62DB\u6765\u4EBA\u4EEC\u4E0D\u7981\u7684\u6076\u610F\u3002</p><p>\u62FFVue.js\u4E3E\u4E00\u4E2A\u5C0F\u4F8B\u5B50\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/35609a7cc06746cb8e36b3a739598e35~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (17).png"></p><p>\u5F53\u6211\u4EEC\u521B\u5EFA\u4E00\u4E2AVue.js\u5E94\u7528\u5B9E\u4F8B\u5E76\u8BD5\u56FE\u5C06\u5176\u6302\u8F7D\u5230\u4E00\u4E2A\u4E0D\u5B58\u5728\u7684DOM\u8282\u70B9<code>not-exist</code>\u4E0A\u65F6\uFF0C\u5C31\u4F1A\u53D7\u5230\u4E00\u6761\u6765\u81EAVue.js\u7684\u8B66\u544A\u4FE1\u606F\uFF0C\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/3f5123ae4abe45f6a784b8eca3730375~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (18).png"></p><p>\u8FD9\u6761\u4FE1\u606F\u6E05\u6670\u5730\u544A\u8BC9\u6211\u4EEC\u6302\u8F7D\u5931\u8D25\u4E86\uFF0C\u5E76\u8BF4\u660E\u4E86\u5931\u8D25\u7684\u539F\u56E0\uFF0C\u4ECE\u800C\u8BA9\u6211\u4EEC\u80FD\u591F\u636E\u6B64\u6E05\u6670\u5FEB\u901F\u5730\u5B9A\u4F4D\u95EE\u9898\u4F4D\u7F6E\u5E76\u7EA0\u6B63\u3002\u8BD5\u60F3\u4E00\u4E0B\uFF0C\u5982\u679CVue.js\u5185\u90E8\u4E0D\u5BF9\u9519\u8BEF\u4FE1\u606F\u505A\u4EFB\u4F55\u7684\u5904\u7406\uFF0C\u90A3\u4E48\u6211\u4EEC\u5F88\u53EF\u80FD\u5F97\u5230\u7684\u662FJavaScript\u5C42\u9762\u7684\u9519\u8BEF\u4FE1\u606F\uFF0C\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/b45c6750096e4331800564459045d24e~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (19).png"></p><p>\u8FD9\u662F\u4E00\u79CD\u591A\u4E48\u4EE4\u4EBA\u6293\u72C2\u7684\u60C5\u666F\uFF0C\u5C24\u5176\u4F1A\u5BF9\u65B0\u5165\u95E8\u7684\u6CA1\u6709\u4EC0\u4E48\u5F00\u53D1\u7ECF\u9A8C\u7684\u7A0B\u5E8F\u5458\u9884\u5907\u5F79\u9020\u6210\u6BC1\u706D\u6027\u6253\u51FB\uFF0C\u5C31\u597D\u6BD4\u4E0B\u8F7D\u4E00\u4E2AVScode\u800C\u4E0D\u5141\u8BB8\u4F7F\u7528\u63D2\u4EF6\uFF0C\u90A3\u6211\u2026\u2026\u8FD8\u4E0B\u8F7D\u5B83\u5E72\u561B\uFF1F\uFF1F\uFF1F</p><p>\u9664\u4E86\u63D0\u4F9B\u5FC5\u8981\u7684\u8B66\u544A\u4FE1\u606F\u5916\uFF0C\u8FD8\u6709\u8BB8\u591A\u80FD\u591F\u6709\u6548\u63D0\u5347\u7528\u6237\u4F53\u9A8C\u7684\u65B9\u6CD5\uFF0C\u6BD4\u5982\u5728\u67D0\u4E9B\u6761\u4EF6\u4E0B\u76F4\u89C2\u5316<code>RefImpl</code>\u7B49\u54CD\u5E94\u5F0F\u6570\u636E\u7C7B\u578B\u7684\u8F93\u51FA\uFF0C\u5728\u8FD9\u91CC\u5C31\u4E0D\u7EC6\u8BF4\u4E86\u3002\u603B\u4E4B\uFF0C\u6846\u67B6\u7684\u8BBE\u8BA1\u8981\u5C3D\u91CF\u5730\u964D\u4F4E\u521D\u5B66\u8005\u7684\u5B66\u4E60\u6210\u672C\uFF0C\u90A3\u4E9B\u53CD\u4EBA\u7C7B\u7684\u8BBE\u8BA1\u5927\u53EF\u4E0D\u5FC5\u3002</p><h2 id="\u63A7\u5236\u6846\u67B6\u4EE3\u7801\u7684\u4F53\u79EF" tabindex="-1"><a class="header-anchor" href="#\u63A7\u5236\u6846\u67B6\u4EE3\u7801\u7684\u4F53\u79EF" aria-hidden="true">#</a> \u63A7\u5236\u6846\u67B6\u4EE3\u7801\u7684\u4F53\u79EF</h2><p>\u6846\u67B6\u7684\u5927\u5C0F\u4E5F\u662F\u8861\u91CF\u4E00\u4E2A\u6846\u67B6\u662F\u5426\u4F18\u79C0\u7684\u6807\u51C6\u4E4B\u4E00\u3002\u6BD5\u7ADF\uFF0C\u5728\u5B9E\u73B0\u540C\u6837\u529F\u80FD\u7684\u60C5\u51B5\u4E0B\uFF0C\u5F53\u7136\u662F\u6240\u7528\u7684\u4EE3\u7801\u91CF\u8D8A\u5C11\u4F53\u79EF\u8D8A\u5C0F\uFF0C\u6700\u540E\u6D4F\u89C8\u5668\u52A0\u8F7D\u8D44\u6E90\u7684\u8017\u65F6\u624D\u8D8A\u5C11\u3002</p><p>\u90A3\u4E48\uFF0C\u5982\u4F55\u51CF\u5C0F\u9879\u76EE\u6253\u5305\u4F53\u79EF\u5462\uFF1F\u6211\u60F3\uFF0C\u5B9E\u9645\u5F00\u53D1\u8FC7\u9879\u76EE\u7684\u4EBA\u5E94\u8BE5\u5BF9\u4E00\u4E2A\u9879\u76EE\u5206\u4E3A\u5F00\u53D1\u7248\u672C\u548C\u751F\u4EA7\u7248\u672C\u3001\u9879\u76EE\u4F9D\u8D56\u5206\u4E3A\u5F00\u53D1\u4F9D\u8D56\u548C\u751F\u4EA7\u4F9D\u8D56\u6709\u6240\u4E86\u89E3\uFF0C\u8FD9\u5C31\u662F\u4E00\u79CD\u901A\u7528\u7684\u5C3D\u53EF\u80FD\u51CF\u5C0F\u9879\u76EE\u4EE3\u7801\u4F53\u79EF\u7684\u624B\u6BB5\u3002\u8B6C\u5982\uFF0C\u5728\u9879\u76EE\u5F00\u53D1\u4E2D\uFF0C\u6E05\u6670\u7CBE\u51C6\u7684\u62A5\u9519\u63D0\u793A\u662F\u5FC5\u4E0D\u53EF\u5C11\u7684\uFF0C\u4F46\u662F\u5230\u4E86\u9879\u76EE\u751F\u4EA7\u90E8\u7F72\u4E2D\uFF0C\u62A5\u9519\u63D0\u793A\u76F8\u5173\u7684\u4EE3\u7801\u5C31\u53EF\u4EE5\u4ECE\u9879\u76EE\u4E4B\u4E2D\u5254\u9664\u6389\u4EE5\u51CF\u5C0F\u4EE3\u7801\u6253\u5305\u4F53\u79EF\uFF0C\u6BD5\u7ADF\u4E00\u4E2A\u9879\u76EE\u7684\u4E0A\u7EBF\u81F3\u5C11\u7ECF\u8FC7\u4E86\u7814\u53D1\u4EBA\u5458\u6700\u57FA\u672C\u7684\u6D4B\u8BD5\uFF0C\u4E0D\u4F1A\u6709\u4EBA\u628A\u5F00\u53D1\u65F6\u62A5\u9519\u505C\u6B62\u8FD0\u884C\u7684\u4EE3\u7801\u8FD8\u90E8\u7F72\u4E0A\u7EBF\u5427\uFF1F</p><p>\u5728Vue.js\u4E2D\uFF0C\u4F7F\u7528\u7684\u6784\u5EFA\u5DE5\u5177\u662F<code>rollup.js</code>\uFF0C\u8BF7\u770B\u4E0B\u5217Vue.js\u6E90\u7801\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6906b918f7894f17b3a49c9730f00ec1~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (22).png"></p><p>\u8FD9\u662F\u4E00\u4E2AVue.js\u7684\u62A5\u9519\u63D0\u793A\uFF0C\u91CC\u9762\u7684<code>__DEV__</code>\u5E38\u91CF\u5B9E\u9645\u4E0A\u5C31\u662F\u901A\u8FC7<code>rollup.js</code>\u7684\u63D2\u4EF6\u914D\u5236\u6765\u9884\u5B9A\u4E49\u7684\uFF1A\u5F53\u9879\u76EE\u5904\u4E8E\u5F00\u53D1\u73AF\u5883\u4E0B\uFF0C\u503C\u4E3A<code>true</code>\uFF0C\u6253\u5370\u62A5\u9519\u4FE1\u606F\uFF1B\u5F53\u9879\u76EE\u5904\u4E8E\u751F\u4EA7\u73AF\u5883\u4E0B\uFF0C\u503C\u4E3A<code>false</code>\uFF0C\u5219\u4E0D\u6253\u5370\u62A5\u9519\u4FE1\u606F\u3002\u6846\u67B6\u6B63\u662F\u901A\u8FC7\u8FD9\u4E9B\u4E0D\u8D77\u773C\u7684\u914D\u7F6E\u6765\u4E00\u6B65\u6B65\u51CF\u5C0F\u9879\u76EE\u6B63\u5F0F\u6253\u5305\u90E8\u7F72\u65F6\u7684\u4EE3\u7801\u4F53\u79EF\u3002</p><h2 id="\u6846\u67B6\u8981\u505A\u5230\u826F\u597D\u7684tree-shaking" tabindex="-1"><a class="header-anchor" href="#\u6846\u67B6\u8981\u505A\u5230\u826F\u597D\u7684tree-shaking" aria-hidden="true">#</a> \u6846\u67B6\u8981\u505A\u5230\u826F\u597D\u7684<code>Tree-Shaking</code></h2><p>\u8FD9\u91CC\u7684<code>Tree-Shaking</code>\u6307\u7684\u662F<strong>\u6D88\u9664\u90A3\u4E9B\u6C38\u8FDC\u4E0D\u4F1A\u88AB\u6267\u884C\u7684\u4EE3\u7801</strong>\uFF0C\u5373\u6392\u9664<code>dead code</code>\uFF08\u6709\u5783\u573E\u56DE\u6536\u673A\u5236\u90A3\u5473\u513F\u4E86\uFF09\u3002\u81F3\u4E8E\u54EA\u4E9B\u4EE3\u7801\u662F\u4E0D\u4F1A\u88AB\u6267\u884C\u7684\uFF0C\u90A3\u5927\u53EF\u4E0D\u5FC5\u5728\u6B64\u7EC6\u8BF4\u3002\u6211\u5C31\u8BF4\u8BF4\u4E00\u4E2A\u6BD4\u8F83\u7279\u6B8A\u7684\u60C5\u51B5\uFF1A\u5728Vue.js\u4E2D\uFF0C\u51E1\u662F\u4E0D\u4F1A\u4EA7\u751F\u526F\u4F5C\u7528\u7684\u7EDF\u7EDF<code>Tree-Shaking</code>\uFF0CVue.js\u624D\u4E0D\u4F1A\u7BA1\u8FD9\u4EE3\u7801\u60F3\u5E72\u561B\u5462\uFF01\uFF08\u526F\u4F5C\u7528\uFF1A\u5F53\u5BF9\u4E00\u4E2A\u51FD\u6570\u7684\u8C03\u7528\u4F1A\u5BF9\u5916\u90E8\u4EA7\u751F\u5F71\u54CD\uFF0C\u5982\u4FEE\u6539\u4E86\u5168\u5C40\u53D8\u91CF\uFF0C\u5C31\u79F0\u8BE5\u51FD\u6570\u6709\u526F\u4F5C\u7528\uFF09</p><p>\u5982\u4E0B\u4EE3\u7801\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/95b2649c8fb14784833f57d3ca2351a8~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (21).png"></p><p>\u867D\u7136\u5728<code>input.js</code>\u6587\u4EF6\u4E2D\u5BFC\u5165\u5E76\u8C03\u7528\u4E86\u51FD\u6570<code>foo</code>\uFF0C\u4F46\u662F\u5728Vue.js\u7684\u6B63\u5F0F\u6253\u5305\u4E4B\u4E2D\uFF0C\u8FD9\u4E00\u90E8\u5206\u8F93\u51FA\u5185\u5BB9\u4E3A\u7A7A\uFF0C\u56E0\u4E3A<code>foo</code>\u51FD\u6570\u5E76\u6CA1\u6709\u526F\u4F5C\u7528\uFF0C\u5C31\u4E0D\u4F1A\u88AB\u5305\u542B\u5728\u9879\u76EE\u4EE3\u7801\u4E4B\u4E2D\u3002</p><p>\u6709\u773C\u5C16\u7684\u540C\u5B66\u53EF\u80FD\u5C31\u8981\u95EE\u4E86\uFF0C<code>/*#__PURE__*/</code>\u6709\u4EC0\u4E48\uFF1F\u5176\u5B9E\u8FD9\u5C31\u76F8\u5F53\u4E8E\u4E00\u4E2A\u6807\u7B7E\uFF0C\u5176\u4F5C\u7528\u5C31\u662F\u5411\u6253\u5305\u5DE5\u5177<code>rollup.js</code>\u62C5\u4FDD\uFF1A\u5BF9\u4E8E<code>foo</code>\u51FD\u6570\u7684\u8C03\u7528\u7EDD\u5BF9\u4E0D\u4F1A\u4EA7\u751F\u526F\u4F5C\u7528\uFF0C\u4F60\u5C31\u653E\u5FC3\u5FEB\u4E50\u7684<code>Tree-Shaking</code>\u5427\u3002\u4E3A\u4EC0\u4E48\u9700\u8981\u8FD9\u6837\u201C\u58F0\u660E\u201D\u5462\uFF1F\u4F60\u8981\u77E5\u9053\uFF0CJavaScript\u662F\u4E00\u95E8\u52A8\u6001\u8BED\u8A00\uFF0C\u5B83\u60F3\u9759\u6001\u5206\u6790\u54EA\u4E9B\u4EE3\u7801\u662F<code>dead code</code>\u96BE\u5EA6\u5F88\u5927\uFF0C\u800C\u5982\u679C\u4F60\u5BF9Vue.js\u54CD\u5E94\u5F0F\u539F\u7406\u6709\u6240\u4E86\u89E3\u7684\u8BDD\uFF0C\u4F60\u5C31\u77E5\u9053\u5982\u679Cobj\u662F\u4E00\u4E2A\u7ECF\u8FC7<code>proxy</code>\u4EE3\u7406\u7684\u5BF9\u8C61\uFF0C\u90A3\u4E48<code>foo</code>\u51FD\u6570\u5BF9<code>obj</code>\u5BF9\u8C61\u7684\u8BFB\u53D6\u4F1A\u89E6\u53D1\u4EE3\u7406\u5BF9\u8C61\u7684<code>get</code>\uFF0C\u800C\u5728<code>get</code>\u4E4B\u4E2D\uFF0C\u662F\u6781\u6709\u53EF\u80FD\u4EA7\u751F\u526F\u4F5C\u7528\u7684\uFF0C\u5982\u89E6\u53D1<code>track</code>\u51FD\u6570</p><h2 id="\u6846\u67B6\u5E94\u8BE5\u8F93\u51FA\u600E\u6837\u7684\u6784\u5EFA\u4EA7\u7269" tabindex="-1"><a class="header-anchor" href="#\u6846\u67B6\u5E94\u8BE5\u8F93\u51FA\u600E\u6837\u7684\u6784\u5EFA\u4EA7\u7269" aria-hidden="true">#</a> \u6846\u67B6\u5E94\u8BE5\u8F93\u51FA\u600E\u6837\u7684\u6784\u5EFA\u4EA7\u7269</h2><p>\u4E00\u4E2A\u4F18\u79C0\u7684\u6846\u67B6\u5E94\u8BE5\u6839\u636E\u4F7F\u7528\u573A\u666F\u7684\u4E0D\u540C\u800C\u9009\u62E9\u4E0E\u4E4B\u6700\u7B26\u5408\u7684\u4EA7\u7269\u5F62\u5F0F\u8FDB\u884C\u8F93\u51FA\uFF0C\u4EE5\u9700\u6C42\u4E3A\u8861\u91CF\u56E0\u7D20\u5927\u81F4\u53EF\u5206\u4E3A\u4EE5\u4E0B\u51E0\u7C7B</p><h3 id="\u4F7F\u7528-script-\u6807\u7B7E\u5F15\u5165\u5E76\u76F4\u63A5\u4F7F\u7528" tabindex="-1"><a class="header-anchor" href="#\u4F7F\u7528-script-\u6807\u7B7E\u5F15\u5165\u5E76\u76F4\u63A5\u4F7F\u7528" aria-hidden="true">#</a> \u4F7F\u7528<code>&lt;script&gt;</code>\u6807\u7B7E\u5F15\u5165\u5E76\u76F4\u63A5\u4F7F\u7528</h3><p>\u793A\u4F8B\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6b7c4ed2881f41d682d37fbac0655f16~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (23).png"></p><p>\u5728\u8FD9\u91CC\uFF0CVue.js\u8F93\u51FA\u7684\u662F\u4E00\u79CD<strong>IIFE</strong>\u683C\u5F0F\u7684\u8D44\u6E90\u3002\uFF08<strong>IIFE</strong>\u7684\u5168\u79F0\u4E3A Immediately Invoked Function Expression,\uFF0C\u5373\u201C\u7ACB\u5373\u8C03\u7528\u7684\u51FD\u6570\u8868\u8FBE\u5F0F\u201D\uFF0C\u5728\u300A\u4F60\u4E0D\u77E5\u9053\u7684JavaScript \u4E0A\u5377\u300B\u4E2D\u4E5F\u6709\u4ECB\u7ECD\uFF09\u5B9E\u9645\u4E0A\uFF0Cvue,global.js\u5C31\u662F\u4E00\u79CD<strong>IIFE</strong>\u683C\u5F0F\u7684\u8D44\u6E90\uFF0C\u5F53\u4F7F\u7528<code>&lt;strict&gt;</code>\u6807\u7B7E\u76F4\u63A5\u5F15\u5165\u8BE5\u6587\u4EF6\u540E\uFF0C\u5168\u5C40\u53D8\u91CFvue\u5C31\u662F\u53EF\u7528\u7684\u4E86\u3002</p><h3 id="\u4F7F\u7528-script-type-module-\u76F4\u63A5\u5F15\u5165esm\u683C\u5F0F\u7684\u8D44\u6E90" tabindex="-1"><a class="header-anchor" href="#\u4F7F\u7528-script-type-module-\u76F4\u63A5\u5F15\u5165esm\u683C\u5F0F\u7684\u8D44\u6E90" aria-hidden="true">#</a> \u4F7F\u7528<code>&lt;script type=&quot;module&quot;&gt;</code>\u76F4\u63A5\u5F15\u5165ESM\u683C\u5F0F\u7684\u8D44\u6E90</h3><p>\u793A\u4F8B\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/b0463f4828f34e70a9199809bb3867cd~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (24).png"></p><p>\u4EE5\u524D\u662F\u4E0D\u652F\u6301\u7684\uFF0C\u4F46\u662F\u968F\u7740\u6280\u672F\u7684\u53D1\u5C55\u4EE5\u53CA\u4E3B\u6D41\u6D4F\u89C8\u5668\u7248\u672C\u7684\u66F4\u65B0\u8FED\u4EE3\uFF0C\u73B0\u5982\u4ECA\u5BF9\u539F\u751FESM\u7684\u652F\u6301\u90FD\u8FD8\u4E0D\u9519\u3002\u5F53\u7136\uFF0C\u4E3A\u4E86\u80FD\u591F\u6B63\u5E38\u8F93\u51FAESM\u683C\u5F0F\u7684\u8D44\u6E90\uFF0C<code>rollup.js</code>\u7684\u8F93\u51FA\u683C\u5F0F\u9700\u8981\u914D\u7F6E\u4E3A\uFF1A<code>format: &#39;esm&#39;</code></p><h2 id="\u5728node-js\u4E2D\u901A\u8FC7require\u8BED\u53E5\u5F15\u5165\u8D44\u6E90" tabindex="-1"><a class="header-anchor" href="#\u5728node-js\u4E2D\u901A\u8FC7require\u8BED\u53E5\u5F15\u5165\u8D44\u6E90" aria-hidden="true">#</a> \u5728Node.js\u4E2D\u901A\u8FC7<code>require</code>\u8BED\u53E5\u5F15\u5165\u8D44\u6E90</h2><p>\u793A\u4F8B\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/3d7f37f66b8444469d8878c50b2191aa~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (25).png"></p><p>\u5728<strong>\u670D\u52A1\u7AEF\u6E32\u67D3</strong>\u4E2D\uFF0C\u8FD9\u79CD\u5F15\u5165\u8D44\u6E90\u65B9\u5F0F\u7684\u652F\u6301\u662F\u6709\u5FC5\u8981\u7684\u3002\u6BD5\u7ADF\uFF0C\u5728\u670D\u52A1\u7AEF\u6E32\u67D3\u4E4B\u4E2D\uFF0CVue.js\u7684\u4EE3\u7801\u5DF2\u7ECF\u4E0D\u50CF\u524D\u6587\u4E00\u6837\u8FD0\u884C\u5728\u6D4F\u89C8\u5668\u73AF\u5883\uFF0C\u800C\u662F\u8FD0\u884C\u5728Node.js\u73AF\u5883\u4E4B\u4E2D\uFF0C\u6B64\u65F6\u8D44\u6E90\u7684\u6A21\u5757\u683C\u5F0F\u5E94\u4E3A<code>CommonJS</code>\uFF0C\u7B80\u79F0<code>cjs</code>\u3002\u914D\u5957\u7684\uFF0C\u4E3A\u4E86\u80FD\u591F\u6B63\u5E38\u8F93\u5165<code>cjs</code>\u6A21\u5757\u7684\u8D44\u6E90\uFF0C\u9700\u8981\u4FEE\u6539<code>rollup.js</code>\u7684\u914D\u7F6E\u4E3A<code>format: &#39;cjs&#39;</code></p><h2 id="\u7279\u6027\u5F00\u5173" tabindex="-1"><a class="header-anchor" href="#\u7279\u6027\u5F00\u5173" aria-hidden="true">#</a> \u7279\u6027\u5F00\u5173</h2><p>\u7279\u6027\u5F00\u5173\u7684\u5B58\u5728\u4E3A\u6846\u67B6\u8BBE\u8BA1\u5E26\u6765\u4E86\u7075\u6D3B\u6027\u3002\u7528\u6237\u53EF\u4EE5\u901A\u8FC7\u7279\u6027\u5F00\u5173\u6765\u8BBE\u7F6E\u5173\u95ED\u9879\u76EE\u4E2D\u4E0D\u9700\u8981\u7684\u7279\u6027\uFF0C\u4ECE\u800C\u5229\u7528<code>Tree-Shaking</code>\u673A\u5236\u51CF\u5C0F\u6700\u7EC8\u4EE3\u7801\u4F53\u79EF\uFF1B\u4E5F\u53EF\u4EE5\u5229\u7528\u7279\u6027\u5F00\u5173\u4EFB\u610F\u4E3A\u6846\u67B6\u6DFB\u52A0\u65B0\u7684\u7279\u6027\u5E76\u9009\u62E9\u662F\u5426\u4F7F\u7528\u3002</p><p>\u5176\u4E2D\uFF0C\u6211\u8BA4\u4E3A\u6700\u5177\u6709\u6807\u5FD7\u6027\u7684\u53EF\u80FD\u5C31\u662F<strong>Vue.js 3</strong>\u4E2D\u9009\u9879\u5F0FAPI\u4E0E\u7EC4\u5408\u5F0FAPI\u5171\u5B58\uFF0C\u5982\u679C\u4F60\u53EA\u60F3\u4F7F\u7528\u7EC4\u5408\u5F0FAPI\uFF0C\u90A3\u4E48\u5B8C\u5168\u53EF\u4EE5\u5229\u7528\u7279\u6027\u5F00\u5173\u5173\u95ED\u9009\u9879\u5F0FAPI\uFF0C\u8FD9\u6837<strong>Vue.js 3</strong>\u4E2D\u4E0E\u9009\u9879API\u76F8\u5173\u7684\u8FD9\u90E8\u5206\u4EE3\u7801\u5C31\u4E0D\u4F1A\u5305\u542B\u5728\u6700\u7EC8\u7684\u4EE3\u7801\u4E2D\uFF0C\u53CD\u4E4B\u4EA6\u7136\u3002</p><h2 id="\u9519\u8BEF\u5904\u7406" tabindex="-1"><a class="header-anchor" href="#\u9519\u8BEF\u5904\u7406" aria-hidden="true">#</a> \u9519\u8BEF\u5904\u7406</h2><p>\u9519\u8BEF\u5904\u7406\u662F\u6846\u67B6\u5F00\u53D1\u8FC7\u7A0B\u4E2D\u975E\u5E38\u91CD\u8981\u7684\u4E00\u4E2A\u73AF\u8282\uFF0C\u8FD9\u4E2A\u673A\u5236\u7684\u597D\u574F\u76F4\u63A5\u51B3\u5B9A\u4E86\u7528\u6237\u5E94\u7528\u7A0B\u5E8F\u7684\u5065\u58EE\u6027\u4EE5\u53CA\u7528\u6237\u5728\u5F00\u53D1\u8FC7\u7A0B\u4E2D\u5904\u7406\u9519\u8BEF\u7684\u5FC3\u667A\u8D1F\u62C5\u3002</p><p>\u5047\u8BBE\u6846\u67B6\u4E0D\u5177\u5907\u9519\u8BEF\u5904\u7406\u673A\u5236\uFF0C\u90A3\u7528\u6237\u7684\u4F7F\u7528\u4F53\u9A8C\u5C31\u4F1A\u975E\u5E38\u4E0D\u597D\u3002\u6B64\u65F6\uFF0C\u5047\u5982\u7528\u6237\u63D0\u4F9B\u7684\u56DE\u8C03\u51FD\u6570\u5728\u6267\u884C\u65F6\u51FA\u9519\u4E86\uFF0C\u90A3\u4E48\u7528\u6237\u5C31\u9700\u8981\u81EA\u5DF1\u6267\u884C<code>try...catch</code>\uFF0C\u4E00\u4E24\u4E2A\u8FD8\u597D\uFF0C\u4F46\u5982\u679C\u6709\u51E0\u5341\u4E0A\u767E\u4E2A\u7C7B\u4F3C\u7684\u51FD\u6570\u9700\u8981\u5904\u7406\u5462\uFF0C\u96BE\u9053\u8FD8\u5728\u4F7F\u7528\u7684\u65F6\u5019\u9010\u4E00\u6DFB\u52A0\u9519\u8BEF\u5904\u7406\u7A0B\u5E8F\uFF1F\u90A3\u6211\u8FD8\u4E0D\u5982\u8F6C\u884C\u53BB\u5B66\u751F\u7269\u517B\u9C7C\u5462\uFF0C\u6765\u53D7\u8FD9\u7F6A\u5E72\u561B\u5462\u3002\uFF08\u6211\u5C31\u662F\u751F\u7269\u4E13\u4E1A\u7684\uFF0C\u4E0A\u5B66\u671F\u8FD8\u5728\u91CE\u5916\u5B9E\u4E60\u6293\u873B\u8713\u3001\u6293\u8783\u87F9\uFF0C\u611F\u89C9\u5B66\u4E60\u8BA1\u7B97\u673A\u76F8\u5173\u77E5\u8BC6\u7684\u65F6\u95F4\u5B8C\u5168\u4E0D\u591F\u7528\u554A\uFF0C\u6CEA\u76EE\uFF09</p><p>\u5E78\u597D\uFF0C\u5982Vue.js\u8FD9\u6837\u7684\u6846\u67B6\u63D0\u4F9B\u4E86\u9519\u8BEF\u5904\u7406\u673A\u5236\uFF0C\u57FA\u672C\u539F\u7406\u5982\u4E0B:</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/30d73a00bf1d404fa2456c2300c8fd23~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (26).png"></p><p>\u5173\u4E8E\u9519\u8BEF\u5904\u7406\u66F4\u591A\u7684\u7EC6\u8282\u53EF\u4EE5\u5728Vue.js\u7684\u6E90\u7801\u4E2D\u641C\u7D22<code>callWithErrorHandling</code>\u51FD\u6570</p><h2 id="\u826F\u597D\u7684typrescript\u7C7B\u578B\u652F\u6301" tabindex="-1"><a class="header-anchor" href="#\u826F\u597D\u7684typrescript\u7C7B\u578B\u652F\u6301" aria-hidden="true">#</a> \u826F\u597D\u7684TypreScript\u7C7B\u578B\u652F\u6301</h2><p>\u73B0\u5982\u4ECA\uFF0CTypeScript\u7AD9\u5728\u5DE8\u4EBAJavaScript\u7684\u80A9\u8180\u4E0A\u51ED\u7740\u66F4\u52A0\u4E30\u5BCC\u7684\u8BED\u8A00\u7279\u6027\u53CA\u529F\u80FD\u83B7\u5F97\u4E86\u8D8A\u6765\u8D8A\u591A\u5F00\u53D1\u8005\u4EE5\u53CA\u5F00\u53D1\u56E2\u961F\u7684\u9752\u7750\uFF0CGitHub\u4E0A\u66FE\u7528JavaScript\u5F00\u53D1\u7684\u8BB8\u591A\u660E\u661F\u9879\u76EE\u90FD\u52A0\u5165\u4E86\u7528TypeScript\u91CD\u5199\u7684\u6D6A\u6F6E\uFF0C\u5BF9TS\u7C7B\u578B\u7684\u652F\u6301\u662F\u5426\u5B8C\u5584\u4E5F\u6E10\u6E10\u6210\u4E3A\u8BC4\u4EF7\u4E00\u4E2A\u6846\u67B6\u662F\u5426\u4F18\u79C0\u7684\u91CD\u8981\u6307\u6807\u4E4B\u4E00\u3002</p><p>\u90A3\u5982\u4F55\u8861\u91CF\u4E00\u4E2A\u6846\u67B6\u5BF9TS\u7C7B\u578B\u652F\u6301\u7684\u6C34\u5E73\u5462\uFF1F\u5982\u679C\u4F60\u89C9\u5F97\u53EA\u8981\u4F7F\u7528\u4E86TS\u7F16\u5199\u6846\u67B6\u5C31\u4EE3\u8868\u5BF9TS\u7C7B\u578B\u652F\u6301\u53CB\u597D\uFF0C\u90A3\u5C31\u5927\u9519\u7279\u9519\u4E86\u3002\u5728\u7F16\u5199\u5927\u578B\u6846\u67B6\u65F6\uFF0C\u60F3\u8981\u505A\u5230\u5B8C\u5584\u7684TS\u7C7B\u578B\u652F\u6301\u5F88\u4E0D\u5BB9\u6613\uFF0C\u76F8\u6BD4JS\u800C\u8A00TS\u8981\u6D88\u8017\u5927\u91CF\u7CBE\u529B\u6765\u505A\u7C7B\u578B\u63A8\u5BFC\uFF0C\u8FD9\u624D\u662FTS\u7C7B\u578B\u652F\u6301\u7684\u5173\u952E\u6240\u5728\u3002</p><p>\u5728\u6211\u770B\u6765\uFF0C\u4E00\u4E2A\u4E0D\u505A\u7C7B\u578B\u63A8\u5BFC\u7684TS\u6587\u4EF6\u4EC5\u4EC5\u662F\u4E3A\u4E00\u4E2AJS\u6587\u4EF6\u6362\u4E86\u4E2A\u540E\u7F00\u800C\u5DF2\uFF0C\u8BF7JS\u5C11\u6765\u78B0\u74F7TS\uFF0C\u8C22\u8C22\uFF01</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/ce1a147e0190430aaadcdf021558f0de~tplv-k3u1fbpfcp-watermark.image?" alt="3c4a9332946018edf53f450869c0ca58.jpeg"></p>',53);function o(d,r){return a}var s=c(p,[["render",o]]);export{s as default};
